import os
from typing import List

import modal

MODEL_NAME = "sentence-transformers/all-MiniLM-L6-v2"
VOLUME_NAME = "modal-gpu-embedding-service-vol"
SECRET_NAME = "modal-gpu-embedding-service-secret"
DICT_NAME = "modal-gpu-embedding-service-output"

image = (
    modal.Image.debian_slim()
    .pip_install(
        "fastapi==0.110.0",
        "pydantic==2.6.4",
        "requests==2.31.0",
        "sentence-transformers==2.6.1",
        "torch==2.2.1",
    )
)

app = modal.App("modal-gpu-embedding-service")
model_cache = modal.Volume.from_name(VOLUME_NAME, create_if_missing=True)
secret = modal.Secret.from_name(SECRET_NAME)


def _validate_api_key(incoming_key: str) -> bool:
    return incoming_key == os.environ.get("API_KEY")


@app.cls(
    gpu="T4",
    image=image,
    volumes={"/model-cache": model_cache},
    secrets=[secret],
)
class EmbeddingService:
    def __init__(self) -> None:
        self.model = None
        self.embedding_dim = 0
        self.total_requests = 0

    @modal.enter()
    def load_model(self) -> None:
        from sentence_transformers import SentenceTransformer

        self.model = SentenceTransformer(MODEL_NAME, cache_folder="/model-cache")
        self.embedding_dim = self.model.get_sentence_embedding_dimension()

    @modal.asgi_app()
    def fastapi_app(self):
        from fastapi import FastAPI, Header, HTTPException
        from pydantic import BaseModel

        api = FastAPI()

        class EmbeddingRequest(BaseModel):
            texts: List[str]

        @api.post("/embeddings")
        async def embeddings(
            payload: EmbeddingRequest,
            x_api_key: str | None = Header(default=None, alias="x-api-key"),
        ):
            if not x_api_key or not _validate_api_key(x_api_key):
                raise HTTPException(status_code=401, detail="Unauthorized")

            vectors = self.model.encode(payload.texts, normalize_embeddings=False)
            self.total_requests += 1
            return {"embeddings": vectors.tolist()}

        return api

    @modal.method()
    def get_stats(self) -> dict:
        return {
            "model_name": MODEL_NAME,
            "total_requests": self.total_requests,
            "embedding_dim": self.embedding_dim,
        }


@app.local_entrypoint()
def populate_stats():
    import requests

    service = modal.Function.lookup(
        "modal-gpu-embedding-service",
        "EmbeddingService.fastapi_app",
    )
    url = f"{service.web_url}/embeddings"

    response = requests.post(
        url,
        headers={"x-api-key": "test-embedding-key-2024"},
        json={"texts": ["modal gpu embeddings", "fastapi service"]},
        timeout=60,
    )
    response.raise_for_status()

    stats = EmbeddingService().get_stats.remote()
    stats_dict = modal.Dict.from_name(DICT_NAME, create_if_missing=True)
    stats_dict.update(stats)
